'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { MOCK_ACTIVITIES } from '@/data/mockData';

const fadeIn = (d: number) => ({
    initial: { opacity: 0, y: 20 },
    animate: { opacity: 1, y: 0 },
    transition: { duration: 0.5, delay: d },
});

export default function LedgerPage() {
    return (
        <div className="space-y-6 max-w-4xl">
            <motion.div {...fadeIn(0)}>
                <h1 className="text-2xl font-bold text-white">Transparent Activity Ledger</h1>
                <p className="text-sm text-gray-500 mt-1">SHA-256 hashed, timestamped, and verified project activities</p>
            </motion.div>

            {/* Ledger Stats */}
            <motion.div {...fadeIn(0.1)} className="grid grid-cols-3 gap-4">
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-cyan-400">{MOCK_ACTIVITIES.length}</p>
                    <p className="text-xs text-gray-500">Total Activities</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-emerald-400">{MOCK_ACTIVITIES.filter(a => a.verified).length}</p>
                    <p className="text-xs text-gray-500">Verified</p>
                </div>
                <div className="glass-card p-4 text-center">
                    <p className="text-2xl font-bold text-amber-400">{MOCK_ACTIVITIES.filter(a => !a.verified).length}</p>
                    <p className="text-xs text-gray-500">Pending</p>
                </div>
            </motion.div>

            {/* Timeline */}
            <motion.div {...fadeIn(0.2)} className="relative">
                {/* Vertical line */}
                <div className="absolute left-[27px] top-0 bottom-0 w-0.5"
                    style={{ background: 'linear-gradient(to bottom, #06b6d4, #8b5cf6, transparent)' }} />

                <div className="space-y-4">
                    {MOCK_ACTIVITIES.map((activity, i) => (
                        <motion.div
                            key={activity.id}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: 0.1 * i }}
                            className="flex gap-4 relative"
                        >
                            {/* Dot */}
                            <div className="flex-shrink-0 w-[54px] flex items-start justify-center pt-4 z-10">
                                <div className="w-3.5 h-3.5 rounded-full border-2"
                                    style={{
                                        borderColor: activity.verified ? '#10b981' : '#f59e0b',
                                        background: activity.verified ? '#10b98130' : '#f59e0b30',
                                        boxShadow: activity.verified ? '0 0 8px #10b98140' : '0 0 8px #f59e0b40',
                                    }} />
                            </div>

                            {/* Card */}
                            <div className="flex-1 glass-card p-5 mb-0">
                                <div className="flex items-start justify-between mb-2">
                                    <div>
                                        <h3 className="text-sm font-semibold text-white">{activity.description}</h3>
                                        <p className="text-xs text-gray-500 mt-1">
                                            {activity.project_title} • {activity.location}
                                        </p>
                                    </div>
                                    <span className="text-xs px-2 py-1 rounded-lg flex-shrink-0"
                                        style={{
                                            background: activity.verified ? 'rgba(16,185,129,0.1)' : 'rgba(245,158,11,0.1)',
                                            color: activity.verified ? '#10b981' : '#f59e0b',
                                        }}>
                                        {activity.verified ? '✓ Verified' : '⏳ Pending'}
                                    </span>
                                </div>

                                <div className="flex items-center gap-4 mt-3">
                                    <div className="flex items-center gap-1.5">
                                        <span className="text-[10px] text-gray-500">🕐</span>
                                        <span className="text-xs text-gray-400">
                                            {new Date(activity.timestamp).toLocaleString()}
                                        </span>
                                    </div>
                                </div>

                                {/* Hash */}
                                <div className="mt-3 p-3 rounded-lg" style={{ background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.03)' }}>
                                    <p className="text-[10px] text-gray-600 mb-1">SHA-256 Hash</p>
                                    <code className="text-xs font-mono text-cyan-400/70 break-all">{activity.hash}</code>
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>
            </motion.div>
        </div>
    );
}
